import React, { useState } from 'react';

const PolicyInput = ({ onAnalyze }) => {
  const [policyText, setPolicyText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!policyText.trim()) {
      setError('Please enter a privacy policy to analyze');
      return;
    }
    
    try {
      setIsLoading(true);
      setError('');
      await onAnalyze(policyText);
    } catch (err) {
      setError('Failed to analyze policy. Please try again.');
      console.error('Analysis error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="policy-input">
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label htmlFor="policy-text">Paste Privacy Policy Text:</label>
          <textarea
            id="policy-text"
            value={policyText}
            onChange={(e) => setPolicyText(e.target.value)}
            placeholder="Paste the privacy policy text here..."
            rows={10}
            disabled={isLoading}
          />
        </div>
        
        {error && <div className="error-message">{error}</div>}
        
        <button 
          type="submit" 
          className="btn analyze-btn"
          disabled={isLoading || !policyText.trim()}
        >
          {isLoading ? 'Analyzing...' : 'Analyze Policy'}
        </button>
      </form>
      
      <style jsx>{`
        .policy-input {
          background: white;
          border-radius: var(--border-radius);
          padding: 1.5rem;
          box-shadow: var(--box-shadow);
        }
        
        .form-group {
          margin-bottom: 1.5rem;
        }
        
        label {
          display: block;
          margin-bottom: 0.5rem;
          font-weight: 500;
          color: var(--text-color);
        }
        
        textarea {
          width: 100%;
          min-height: 200px;
          padding: 1rem;
          border: 1px solid #ddd;
          border-radius: var(--border-radius);
          font-family: inherit;
          font-size: 1rem;
          line-height: 1.5;
          resize: vertical;
          transition: border-color 0.2s ease, box-shadow 0.2s ease;
        }
        
        textarea:focus {
          border-color: var(--primary-color);
          box-shadow: 0 0 0 2px rgba(74, 111, 165, 0.2);
          outline: none;
        }
        
        .analyze-btn {
          width: 100%;
          font-size: 1.1rem;
          font-weight: 600;
          padding: 1rem;
          margin-top: 1rem;
        }
        
        .error-message {
          color: #e53e3e;
          background-color: #fff5f5;
          border: 1px solid #fc8181;
          border-radius: var(--border-radius);
          padding: 0.75rem 1rem;
          margin-bottom: 1rem;
          font-size: 0.9rem;
        }
        
        /* Mobile styles */
        @media (max-width: 768px) {
          .policy-input {
            padding: 1rem;
            border-radius: 0;
            box-shadow: none;
            margin: 0 -1rem;
          }
          
          textarea {
            min-height: 250px;
            font-size: 16px; /* Prevent iOS zoom */
          }
          
          .analyze-btn {
            padding: 1rem;
            font-size: 1rem;
          }
        }
      `}</style>
    </div>
  );
};

export default PolicyInput;
